import React, { Component } from 'react';
import PropTypes from 'prop-types';
import { Link, NavLink } from 'react-router-dom';
import './Nav.css';

import menuOpen from '../../icons/menu-open.svg';
import menuClose from '../../icons/menu-close.svg';

class Nav extends Component {
  constructor(props) {
    super(props);
    this.state = { isToggleOn: false };

    this.toggleMenu = this.toggleMenu.bind(this);
    this.closeMenu = this.closeMenu.bind(this);
  }

  toggleMenu(e) {
    e.preventDefault();
    this.setState(state => ({
      isToggleOn: !state.isToggleOn,
    }));
  }

  closeMenu() {
    this.setState({
      isToggleOn: false,
    });
  }

  render() {
    const { brand, isHome } = this.props;
    const { isToggleOn } = this.state;
    return (
      <nav className="Nav">
        <Link className={isHome ? 'Nav-brand' : 'Nav-brand back-arrow'} to="/">{brand}</Link>
        <button className="Menu-button" id="menuBtn" type="button" onClick={this.toggleMenu}>
          <img src={isToggleOn ? menuClose : menuOpen} alt="Menu Open Button - Dylan Howard Web and App Design and Development" />
        </button>
        <ul className={isToggleOn ? 'Nav-links-active' : 'Nav-links'}>
          <li className="Nav-link">
            <NavLink to="/work" activeClassName="active" onClick={this.closeMenu}>Work</NavLink>
          </li>
          <li className="Nav-link">
            <NavLink to="/about" activeClassName="active" onClick={this.closeMenu}>About</NavLink>
          </li>
          <li className="Nav-link">
            <NavLink to="/contact" activeClassName="active" onClick={this.closeMenu}>Contact</NavLink>
          </li>
        </ul>
      </nav>
    );
  }
}

Nav.propTypes = {
  brand: PropTypes.string,
  isHome: PropTypes.bool,
};
Nav.defaultProps = {
  brand: '',
  isHome: true,
};

export default Nav;
