import React from 'react';
import PropTypes from 'prop-types';
import Header from '../Header/Header';
import ProgressiveImage from '../ProgressiveImage/ProgressiveImage';
import WorkAPI from '../../WorkAPI';
import './Project.css';

const Project = ({ match }) => {
  const work = WorkAPI.get(
    match.params.slug,
  );
  return (
    <div>
      <Header>
        <h1>{work.title}</h1>
        <p className="Site-hook">
          {work.description}
        </p>
        <p>
          <a className="Bright-link" href={work.link}>Click here to see the demo</a>
        </p>
      </Header>
      <div className="photos-container" id="body">
        <div className="photo">
          <ProgressiveImage
            preview={`../img/prj/pre-${work.image}`}
            image={`../img/prj/${work.image}`}
            alt={`${work.title} - Dylan Howard Web Design and Development`}
          />
        </div>
      </div>
    </div>
  );
};

Project.propTypes = {
  match: PropTypes.shape({
    params: PropTypes.shape({
      slug: PropTypes.string,
    }),
  }),
};
Project.defaultProps = {
  match: {
    params: {
      slug: '',
    },
  },
};

export default Project;
